-- Topic: body (신체·몸)
-- Content: 20 collocations + 20 idioms + 6 nuances = 46 entries
-- ============================================================================

-- ----------------------------------------------------------------------------
-- A. COLLOCATIONS (20 entries: 5 each at B1, B2, C1, C2)
-- ----------------------------------------------------------------------------

INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
-- B1
('col_body_B1_01', 'raise', 'hand', 'raise your hand', '손을 들다', 'lift', '교실에서 질문이나 발표할 때 ''raise''가 자연스러워요. ''lift''는 무거운 물건을 들 때 써요.', 'Please raise your hand if you have a question.', '질문이 있으시면 손을 들어주세요.', 'She raised her hand to answer first.', '그녀는 먼저 답하려고 손을 들었어요.', 'B1', 'body', 1, 'raising hand classroom'),
('col_body_B1_02', 'stretch', 'legs', 'stretch your legs', '다리를 쭉 펴다', 'extend', '오래 앉아 있다가 일어나 걸을 때 ''stretch your legs''라고 해요. 단순히 늘리는 ''extend''와는 뉘앙스가 달라요.', 'Let''s stop the car and stretch our legs.', '차를 세우고 다리 좀 펴봐요.', 'I need to stretch my legs after sitting all day.', '하루 종일 앉아 있어서 다리를 펴야 해요.', 'B1', 'body', 1, 'stretching legs walk'),
('col_body_B1_03', 'hold', 'breath', 'hold your breath', '숨을 참다', 'keep', '잠수하거나 긴장될 때 ''hold''를 써요. ''keep your breath''는 어색해요.', 'Hold your breath when you go underwater.', '물속에 들어갈 때 숨을 참으세요.', 'I held my breath waiting for the results.', '결과를 기다리며 숨을 죽였어요.', 'B1', 'body', 1, 'holding breath underwater'),
('col_body_B1_04', 'rub', 'eyes', 'rub your eyes', '눈을 비비다', 'scratch', '졸리거나 피곤할 때 부드럽게 비비는 동작은 ''rub''이에요. ''scratch''는 가려움을 긁는 거예요.', 'Don''t rub your eyes when they itch.', '눈이 가려울 때 비비지 마세요.', 'He rubbed his eyes and yawned.', '그는 눈을 비비며 하품을 했어요.', 'B1', 'body', 1, 'rubbing eyes tired'),
('col_body_B1_05', 'shake', 'hands', 'shake hands', '악수하다', 'hold', '인사로 손을 흔들어 잡는 행위는 ''shake hands''예요. ''hold hands''는 연인이 손을 잡는 거예요.', 'They shook hands after the meeting.', '회의 후에 그들은 악수했어요.', 'Let''s shake hands and forget about it.', '악수하고 잊어버려요.', 'B1', 'body', 1, 'shaking hands business'),

-- B2
('col_body_B2_01', 'tense', 'muscles', 'tense up your muscles', '근육이 긴장되다', 'harden', '스트레스나 추위로 근육이 굳을 때 ''tense up''을 써요. ''harden''은 물체가 단단해지는 느낌이에요.', 'My muscles tense up when I''m stressed.', '스트레스를 받으면 근육이 긴장돼요.', 'Try not to tense up your shoulders.', '어깨에 힘을 주지 않도록 해보세요.', 'B2', 'body', 2, 'tense muscles stress'),
('col_body_B2_02', 'loosen', 'joints', 'loosen up your joints', '관절을 풀다', 'open', '운동 전에 몸을 풀 때 ''loosen up''이 자연스러워요. ''open''은 관절에 어색해요.', 'Loosen up your joints before running.', '달리기 전에 관절을 풀어주세요.', 'Gentle stretches will loosen up your joints.', '가벼운 스트레칭이 관절을 풀어줘요.', 'B2', 'body', 2, 'joint stretching warmup'),
('col_body_B2_03', 'regain', 'consciousness', 'regain consciousness', '의식을 되찾다', 'recover', '기절했다가 깨어날 때 ''regain consciousness''가 정확해요. ''recover''는 회복 전반에 써요.', 'He regained consciousness after a few minutes.', '그는 몇 분 후에 의식을 되찾았어요.', 'The patient slowly regained consciousness.', '환자는 천천히 의식을 회복했어요.', 'B2', 'body', 2, 'regain consciousness hospital'),
('col_body_B2_04', 'lose', 'balance', 'lose your balance', '균형을 잃다', 'drop', '미끄러지거나 휘청거릴 때 ''lose your balance''예요. ''drop''은 떨어뜨리는 거예요.', 'I lost my balance on the icy road.', '얼어붙은 길에서 균형을 잃었어요.', 'She lost her balance and fell off the bike.', '그녀는 균형을 잃고 자전거에서 떨어졌어요.', 'B2', 'body', 2, 'losing balance slip'),
('col_body_B2_05', 'catch', 'breath', 'catch your breath', '숨을 고르다', 'take', '달리고 난 후 숨을 고를 때 ''catch one''s breath''예요. ''take a breath''는 한 번 들이쉬는 거예요.', 'Let me catch my breath before we continue.', '계속하기 전에 숨 좀 고를게요.', 'She paused to catch her breath at the top.', '그녀는 정상에서 숨을 고르려고 멈췄어요.', 'B2', 'body', 2, 'catching breath after running'),

-- C1
('col_body_C1_01', 'strengthen', 'core', 'strengthen the core', '코어를 강화하다', 'thicken', '복부와 허리 근육군을 단련할 때 ''strengthen''을 써요. ''thicken''은 살이 두꺼워지는 느낌이라 어색해요.', 'Planks help strengthen the core effectively.', '플랭크는 코어 강화에 효과적이에요.', 'A strong core improves overall posture.', '강한 코어는 전체 자세를 개선해요.', 'C1', 'body', 2, 'core workout plank'),
('col_body_C1_02', 'improve', 'posture', 'improve your posture', '자세를 개선하다', 'fix', '점진적인 자세 교정에는 ''improve''가 자연스러워요. ''fix''는 즉각적인 수리 느낌이에요.', 'Yoga can improve your posture over time.', '요가는 시간이 지나면서 자세를 개선해줘요.', 'Sit up straight to improve your posture.', '자세를 개선하려면 똑바로 앉으세요.', 'C1', 'body', 2, 'good posture office'),
('col_body_C1_03', 'maintain', 'flexibility', 'maintain flexibility', '유연성을 유지하다', 'keep', '꾸준한 노력으로 유지한다는 뉘앙스는 ''maintain''이에요. ''keep''보다 격식 있어요.', 'Daily stretching helps maintain flexibility.', '매일 스트레칭하면 유연성을 유지할 수 있어요.', 'Dancers must maintain flexibility throughout their career.', '무용수들은 평생 유연성을 유지해야 해요.', 'C1', 'body', 2, 'flexibility yoga stretch'),
('col_body_C1_04', 'build', 'endurance', 'build endurance', '지구력을 기르다', 'grow', '점차 쌓아 올리는 의미로 ''build''가 적합해요. ''grow''는 자연적인 성장 느낌이에요.', 'Long runs help build endurance.', '장거리 달리기는 지구력을 길러줘요.', 'It takes months to build endurance for a marathon.', '마라톤을 위한 지구력을 기르는 데는 몇 달이 걸려요.', 'C1', 'body', 2, 'endurance training running'),
('col_body_C1_05', 'ease', 'tension', 'ease tension', '긴장을 풀어주다', 'remove', '서서히 완화시킬 때 ''ease''가 자연스러워요. ''remove''는 완전히 제거하는 강한 의미예요.', 'A warm bath can ease muscle tension.', '따뜻한 목욕은 근육 긴장을 풀어줘요.', 'Deep breathing helps ease tension in the body.', '심호흡은 몸의 긴장을 풀어줘요.', 'C1', 'body', 2, 'easing tension massage'),

-- C2
('col_body_C2_01', 'alleviate', 'strain', 'alleviate strain', '근육 통증을 완화하다', 'remove', '의학적·격식 있는 완화는 ''alleviate''예요. ''remove''는 너무 절대적이에요.', 'Proper ergonomics can alleviate strain on the back.', '올바른 인체공학은 허리 부담을 완화해줘요.', 'Physical therapy helps alleviate strain in the joints.', '물리치료는 관절의 부담을 완화해줘요.', 'C2', 'body', 3, 'back strain relief therapy'),
('col_body_C2_02', 'rehabilitate', 'injury', 'rehabilitate an injury', '부상을 재활하다', 'cure', '재활 과정 전체는 ''rehabilitate''예요. ''cure''는 단발성 치료 느낌이에요.', 'Athletes rehabilitate injuries with specialized programs.', '운동선수들은 전문 프로그램으로 부상을 재활해요.', 'It took six months to rehabilitate her knee injury.', '무릎 부상을 재활하는 데 6개월이 걸렸어요.', 'C2', 'body', 3, 'injury rehabilitation physio'),
('col_body_C2_03', 'restore', 'mobility', 'restore mobility', '움직임을 회복시키다', 'fix', '잃었던 가동 범위를 되찾을 때 ''restore''예요. ''fix''는 단순 수리예요.', 'Surgery helped restore mobility in his shoulder.', '수술이 그의 어깨 가동성을 회복시켜 줬어요.', 'Targeted exercises can restore mobility after injury.', '맞춤 운동은 부상 후 가동성을 회복시켜요.', 'C2', 'body', 3, 'mobility recovery exercise'),
('col_body_C2_04', 'mitigate', 'inflammation', 'mitigate inflammation', '염증을 줄이다', 'kill', '염증을 점진적으로 줄일 때 ''mitigate''가 격식 있어요. ''kill''은 너무 강한 표현이에요.', 'Ice packs help mitigate inflammation.', '아이스팩은 염증을 줄이는 데 도움이 돼요.', 'Certain foods can mitigate chronic inflammation.', '특정 음식은 만성 염증을 줄여줘요.', 'C2', 'body', 3, 'inflammation reduction ice'),
('col_body_C2_05', 'reinforce', 'musculature', 'reinforce the musculature', '근육 구조를 강화하다', 'thicken', '근육 시스템 전체를 보강하는 격식 표현은 ''reinforce''예요. ''thicken''은 어색해요.', 'Resistance training reinforces the musculature.', '저항 운동은 근육 구조를 강화해요.', 'These exercises reinforce the core musculature.', '이 운동들은 코어 근육 구조를 강화해요.', 'C2', 'body', 3, 'musculature training gym')
ON CONFLICT (id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- B. IDIOMS (20 entries: 5 each at B1, B2, C1, C2)
-- ----------------------------------------------------------------------------

INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
-- B1
('idm_body_B1_01', 'give someone a hand', '도와주다', '누군가에게 손을 주다', '도움을 청하거나 줄 때 자주 써요. ''박수치다''라는 뜻으로도 쓰여서 문맥을 봐야 해요.', 'Can you give me a hand with this box?', '이 상자 옮기는 것 좀 도와주실래요?', 'Let''s give him a hand with the project.', '그 프로젝트 도와줍시다.', NULL, NULL, 'B1', 'body', 1, 'helping hand teamwork', 1),
('idm_body_B1_02', 'see eye to eye', '의견이 일치하다', '눈과 눈을 마주보다', '주로 부정문(don''t see eye to eye)으로 자주 써요. 의견 차이를 부드럽게 표현할 때 좋아요.', 'We don''t always see eye to eye on politics.', '우리는 정치 얘기는 늘 의견이 안 맞아요.', 'I''m glad we see eye to eye on this.', '이 문제에서 의견이 같아서 다행이에요.', NULL, NULL, 'B1', 'body', 1, 'agreement handshake people', 2),
('idm_body_B1_03', 'pull someone''s leg', '농담하다, 놀리다', '누군가의 다리를 당기다', '가벼운 농담을 했을 때 ''Are you pulling my leg?''(농담하는 거예요?)로 자주 들어요.', 'Don''t worry, I''m just pulling your leg.', '걱정 마세요, 그냥 농담하는 거예요.', 'Are you pulling my leg or is it true?', '농담이에요, 정말이에요?', NULL, NULL, 'B1', 'body', 1, 'joking laughing friends', 3),
('idm_body_B1_04', 'lend an ear', '귀 기울여 듣다', '귀를 빌려주다', '진지하게 들어달라고 부탁하거나 들어준다고 할 때 써요. 다정한 뉘앙스예요.', 'Can you lend an ear for a moment?', '잠깐 얘기 좀 들어줄래요?', 'She always lends an ear to her friends.', '그녀는 친구들 얘기를 늘 잘 들어줘요.', NULL, NULL, 'B1', 'body', 1, 'listening conversation friend', 4),
('idm_body_B1_05', 'by word of mouth', '입소문으로', '입의 말로', '광고가 아닌 사람들 사이에서 전해지는 정보를 말할 때 써요.', 'The restaurant became famous by word of mouth.', '그 식당은 입소문으로 유명해졌어요.', 'News spread quickly by word of mouth.', '소식은 입소문으로 빠르게 퍼졌어요.', NULL, NULL, 'B1', 'body', 1, 'word of mouth gossip', 5),

-- B2
('idm_body_B2_01', 'cost an arm and a leg', '엄청 비싸다', '팔과 다리만큼의 비용이 들다', '가격이 부담스럽게 비쌀 때 과장해서 써요. 비격식 대화에서 자연스러워요.', 'That designer bag costs an arm and a leg.', '그 명품 가방은 엄청 비싸요.', 'A wedding can cost an arm and a leg.', '결혼식은 정말 돈이 많이 들어요.', NULL, NULL, 'B2', 'body', 2, 'expensive luxury price', 6),
('idm_body_B2_02', 'have a sweet tooth', '단것을 좋아하다', '달콤한 이를 가지다', '디저트나 사탕을 좋아한다고 말할 때 자연스럽게 써요.', 'I have a sweet tooth, so I love desserts.', '단것을 좋아해서 디저트를 사랑해요.', 'She has a sweet tooth for chocolate.', '그녀는 초콜릿이라면 사족을 못 써요.', NULL, NULL, 'B2', 'body', 2, 'sweet tooth dessert cake', 7),
('idm_body_B2_03', 'thick-skinned', '뻔뻔한, 비판에 둔감한', '두꺼운 피부를 가진', '비판을 잘 견디는 사람을 묘사할 때 써요. 반대는 ''thin-skinned''(예민한)예요.', 'You need to be thick-skinned to work in sales.', '영업 일을 하려면 강철 멘탈이 필요해요.', 'Politicians have to be thick-skinned.', '정치인은 비판에 둔감해야 해요.', NULL, NULL, 'B2', 'body', 2, 'thick skinned tough person', 8),
('idm_body_B2_04', 'get cold feet', '겁먹다, 망설이다', '발이 차가워지다', '중요한 결정 직전에 마음이 약해질 때 써요. 결혼식 직전에 자주 쓰는 표현이에요.', 'He got cold feet before the wedding.', '그는 결혼식 직전에 겁을 먹었어요.', 'I''m getting cold feet about quitting my job.', '직장을 그만두는 게 망설여져요.', NULL, NULL, 'B2', 'body', 2, 'cold feet nervous wedding', 9),
('idm_body_B2_05', 'all ears', '귀 기울여 듣는', '온통 귀가 된', '누가 말하려고 할 때 ''I''m all ears''(귀담아 듣고 있어요)로 자주 써요.', 'Tell me everything — I''m all ears.', '다 말해보세요, 잘 듣고 있어요.', 'The kids were all ears during the story.', '아이들은 이야기를 귀담아 들었어요.', NULL, NULL, 'B2', 'body', 2, 'all ears listening attention', 10),

-- C1
('idm_body_C1_01', 'have your hands full', '몹시 바쁘다', '두 손이 가득 차다', '아이를 돌보거나 일이 많을 때 자주 써요. 비격식·격식 모두 가능해요.', 'She has her hands full with three kids.', '그녀는 아이 셋 때문에 정신없이 바빠요.', 'I have my hands full this week.', '이번 주는 정신없이 바빠요.', NULL, NULL, 'C1', 'body', 2, 'hands full busy mom', 11),
('idm_body_C1_02', 'out of your hands', '당신 손을 떠난', '당신 손 밖에', '결정권이 더 이상 자기에게 없을 때 써요. 책임을 회피하는 뉘앙스도 있어요.', 'The decision is out of my hands now.', '이 결정은 이제 제 손을 떠났어요.', 'It''s out of our hands at this point.', '이 시점에선 우리가 어쩔 수 없어요.', NULL, NULL, 'C1', 'body', 2, 'out of hands letting go', 12),
('idm_body_C1_03', 'rule of thumb', '경험에 의한 법칙', '엄지의 규칙', '엄밀한 규칙이 아닌 대략적인 지침을 말할 때 격식 있게 써요.', 'As a rule of thumb, drink eight glasses of water.', '경험상, 물은 하루 8잔 마시세요.', 'A good rule of thumb is to save 20% of income.', '소득의 20%를 저축하는 것이 좋은 지침이에요.', NULL, NULL, 'C1', 'body', 2, 'rule of thumb guideline', 13),
('idm_body_C1_04', 'neck and neck', '막상막하의', '목과 목이 나란히', '경기나 경쟁에서 우열을 가리기 어려울 때 써요. 스포츠 중계에서 자주 들려요.', 'The two runners were neck and neck.', '두 주자는 막상막하였어요.', 'The candidates are neck and neck in the polls.', '후보들은 여론조사에서 박빙이에요.', NULL, NULL, 'C1', 'body', 2, 'neck and neck race close', 14),
('idm_body_C1_05', 'at the back of your mind', '마음 한구석에 (계속) 있는', '마음 뒤편에', '잊지 않고 늘 신경 쓰이는 것을 표현할 때 써요. 부드럽고 사려 깊은 뉘앙스예요.', 'That worry is always at the back of my mind.', '그 걱정이 늘 마음 한구석에 있어요.', 'Keep this advice at the back of your mind.', '이 조언을 늘 마음에 새겨 두세요.', NULL, NULL, 'C1', 'body', 2, 'back of mind thinking worry', 15),

-- C2
('idm_body_C2_01', 'play it by ear', '상황에 맞춰 하다', '귀로 (악보 없이) 연주하다', '미리 계획하지 않고 즉흥적으로 대응할 때 써요. 격식 있는 자리에서도 무방해요.', 'Let''s play it by ear and see what happens.', '상황 봐가면서 합시다.', 'We''ll play it by ear depending on the weather.', '날씨에 따라 즉흥적으로 결정할 거예요.', NULL, NULL, 'C2', 'body', 3, 'play by ear improvise', 16),
('idm_body_C2_02', 'pay through the nose', '바가지 쓰다', '코를 통해 지불하다', '터무니없이 많은 돈을 지불할 때 비판적으로 써요.', 'Tourists pay through the nose at this restaurant.', '관광객들은 이 식당에서 바가지를 써요.', 'We paid through the nose for those concert tickets.', '그 콘서트 티켓에 바가지를 썼어요.', NULL, NULL, 'C2', 'body', 3, 'paying too much overpriced', 17),
('idm_body_C2_03', 'have a chip on your shoulder', '꽁한 마음을 품다', '어깨에 나무 조각을 올려두다', '과거의 불만이나 열등감을 가지고 공격적으로 행동할 때 써요.', 'He''s had a chip on his shoulder since he was fired.', '그는 해고된 이후로 늘 불만이 가득해요.', 'She has a chip on her shoulder about her background.', '그녀는 자기 출신에 대해 꽁해 있어요.', NULL, NULL, 'C2', 'body', 3, 'chip on shoulder resentment', 18),
('idm_body_C2_04', 'bury your head in the sand', '문제를 외면하다', '모래에 머리를 파묻다', '문제를 인정하지 않고 회피하는 태도를 비판할 때 써요.', 'You can''t bury your head in the sand forever.', '문제를 영원히 외면할 수는 없어요.', 'He buried his head in the sand about his debts.', '그는 빚 문제를 외면했어요.', NULL, NULL, 'C2', 'body', 3, 'head in sand avoidance', 19),
('idm_body_C2_05', 'the apple of your eye', '가장 소중한 사람', '눈동자의 사과', '특히 자녀나 사랑하는 사람을 묘사할 때 따뜻하게 써요. 시적인 표현이에요.', 'His daughter is the apple of his eye.', '그의 딸은 눈에 넣어도 안 아픈 존재예요.', 'She''s been the apple of her grandfather''s eye.', '그녀는 할아버지의 보물이에요.', NULL, NULL, 'C2', 'body', 3, 'apple of eye precious child', 20)
ON CONFLICT (id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- C. NUANCES (6 entries)
